for task in records:
    if task.partner_id and task.x_vehicle_id:
        sale_order = env['sale.order'].create({
            'partner_id': task.partner_id.id,
            'x_vehicle_id': task.x_vehicle_id.id,
            'x_chassis_number': task.x_chassis_number,
            'x_task_id': task.id,
        })
        task['sale_order_id'] = sale_order.id
        action = {
            'type': 'ir.actions.act_window',
            'res_model': 'sale.order',
            'view_mode': 'form',
            'res_id': sale_order.id,
        }

for task in records:
    if task.partner_id and task.x_vehicle_id:
        invoice = env['account.move'].create({
            'move_type': 'out_invoice',
            'partner_id': task.partner_id.id,
            'x_vehicle_id': task.x_vehicle_id.id,
            'x_chassis_number': task.x_chassis_number,
            'x_task_id': task.id,
        })
        task['x_is_invoice'] = True
        action = {
            'type': 'ir.actions.act_window',
            'res_model': 'account.move',
            'view_mode': 'form',
            'res_id': invoice.id,
        }

for task in records:
    if task.x_vehicle_id and task.x_odometer:
        env['fleet.vehicle.odometer'].create({
            'value': task.x_odometer,
            'vehicle_id': task.x_vehicle_id.id,
            'driver_id': task.x_vehicle_id.driver_id.id,
        })
